/**
 * Proxy requests to model entity inference endpoints.

All inference requests must resolve to a `VirtualModel`. The platform's
provider reconciler auto-creates an implicit `autoprovisioned` VirtualModel
for every served model entity (named after the entity, with
`default_model_entity` set to the entity ref) so this is the typical case;
operators can also create custom VirtualModels for routing, plugin chains,
LoRA escape-hatches, etc. Requests for which no VirtualModel can be found
return `404`.
 * @summary Model Inference Proxy GET
 */
export const gatewayProxyGet = (
  workspace: string,
  name: string,
  trailingUri: string,
  signal?: AbortSignal
) => {
  return customFetch<unknown>({
    url: `/apis/inference-gateway/v2/workspaces/${encodeURIComponent(String(workspace))}/model/${encodeURIComponent(String(name))}/-/${encodeURIComponent(String(trailingUri))}`,
    method: 'GET',
    signal,
  });
};

export const getGatewayProxyGetQueryKey = (
  workspace: string,
  name: string,
  trailingUri: string
) => {
  return [
    `/apis/inference-gateway/v2/workspaces/${workspace}/model/${name}/-/${trailingUri}`,
  ] as const;
};

export const getGatewayProxyGetQueryOptions = <
  TData = Awaited<ReturnType<typeof gatewayProxyGet>>,
  TError = ErrorType<HTTPValidationError>,
>(
  workspace: string,
  name: string,
  trailingUri: string,
  options?: {
    query?: Partial<UseQueryOptions<Awaited<ReturnType<typeof gatewayProxyGet>>, TError, TData>>;
  }
) => {
  const { query: queryOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGatewayProxyGetQueryKey(workspace, name, trailingUri);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof gatewayProxyGet>>> = ({ signal }) =>
    gatewayProxyGet(workspace, name, trailingUri, signal);

  return {
    queryKey,
    queryFn,
    enabled: !!(workspace && name && trailingUri),
    ...queryOptions,
  } as UseQueryOptions<Awaited<ReturnType<typeof gatewayProxyGet>>, TError, TData> & {
    queryKey: DataTag<QueryKey, TData, TError>;
  };
};

