/**
 * Retrieve information about a specific OpenAI-compatible model.
Workspace is always taken from the URL path; name may be model_entity_name
or workspace/model_entity_name (workspace prefix is ignored).
 * @summary OpenAI Get Model
 */
export const openaiProxyGetModel = (workspace: string, name: string, signal?: AbortSignal) => {
  return customFetch<OpenAIModelResp>({
    url: `/apis/inference-gateway/v2/workspaces/${encodeURIComponent(String(workspace))}/openai/-/v1/models/${encodeURIComponent(String(name))}`,
    method: 'GET',
    signal,
  });
};

