/**
 * List all export jobs with filtering capabilities.

Use `workspace=-` for cross-workspace listing.
 * @summary List Export Jobs
 */
export const listExportJobs = (
  workspace: string,
  params?: ListExportJobsParams,
  signal?: AbortSignal
) => {
  return customFetch<ExportJobsPage>({
    url: `/apis/intake/v2/workspaces/${encodeURIComponent(String(workspace))}/export/jobs`,
    method: 'GET',
    params,
    signal,
  });
};

export const getListExportJobsQueryKey = (workspace: string, params?: ListExportJobsParams) => {
  return [
    `/apis/intake/v2/workspaces/${workspace}/export/jobs`,
    ...(params ? [params] : []),
  ] as const;
};

