/**
 * Export entries to an external file.

Use the `longest_per_thread` filter to export only the longest entry per thread,
which is useful for thread-based exports.

Supported output file URLs:

- NeMo Datastore: nds://workspace/dataset_name
- HuggingFace Dataset: hf://datasets/org/name/path/to/file
- Local filesystem: file:///path/to/export (for development)
 * @summary Create Export Job
 */
export const createExportJob = (
  workspace: string,
  exportJobInput: ExportJobInput,
  signal?: AbortSignal
) => {
  return customFetch<ExportJob>({
    url: `/apis/intake/v2/workspaces/${encodeURIComponent(String(workspace))}/export/jobs`,
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    data: exportJobInput,
    signal,
  });
};

export const getCreateExportJobMutationOptions = <
  TError = ErrorType<HTTPValidationError>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createExportJob>>,
    TError,
    { workspace: string; data: ExportJobInput },
    TContext
  >;
}): UseMutationOptions<
  Awaited<ReturnType<typeof createExportJob>>,
  TError,
  { workspace: string; data: ExportJobInput },
  TContext
> => {
  const mutationKey = ['createExportJob'];
  const { mutation: mutationOptions } = options
    ? options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey } };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof createExportJob>>,
    { workspace: string; data: ExportJobInput }
  > = (props) => {
    const { workspace, data } = props ?? {};

    return createExportJob(workspace, data);
  };

  return { mutationFn, ...mutationOptions };
};

