/**
 * Check the status of an export job.
 * @summary Get Export Job Status
 */
export const getExportJobStatus = (workspace: string, name: string, signal?: AbortSignal) => {
  return customFetch<ExportJob>({
    url: `/apis/intake/v2/workspaces/${encodeURIComponent(String(workspace))}/export/jobs/${encodeURIComponent(String(name))}`,
    method: 'GET',
    signal,
  });
};

export const getGetExportJobStatusQueryKey = (workspace: string, name: string) => {
  return [`/apis/intake/v2/workspaces/${workspace}/export/jobs/${name}`] as const;
};

